INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('春节', '全国', '春节', '农历正月初一，中国民间最盛大、最热闹的传统节日，又称过年。民间习惯贴剪纸、贴年画、贴春联、贴福字，除夕夜守岁、放爆竹，互相走访拜年。2006年列入第一批国家级非物质文化遗产名录。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('元宵节', '全国', '元宵节', '农历正月十五，又称上元节、灯节。民间风俗有扎彩灯、猜灯谜、耍龙灯、舞狮子、踩高跷、划旱船、吃元宵、放风筝等。2008年列入第二批国家级非物质文化遗产名录。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('清明节', '全国', '清明节', '公历4月5日前后，农历二十四节气之一。人们有祭祖、扫墓、踏青之俗。清明节与春节、端午节、中秋节并称为中国四大传统节日。2006年列入第一批国家级非物质文化遗产名录。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('端午节', '全国', '端午节', '农历五月初五，又称端阳节、龙舟节。家家户户吃粽子，南方有赛龙舟等习俗。纪念爱国诗人屈原。2006年列入第一批国家级非物质文化遗产名录，2009年入选世界非物质文化遗产。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('七夕节', '全国', '七夕节', '农历七月初七，传说是牛郎织女天河相会的日子，又称乞巧节、女儿节。过去姑娘们在这一天会穿针乞巧、拜织女，是中国传统节日中最具浪漫色彩的节日。2006年列入第一批国家级非物质文化遗产名录。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('中秋节', '全国', '中秋节', '农历八月十五，民间有祭月、赏月、吃月饼、饮桂花酒之俗，象征团圆。与春节、端午节、清明节并称为中国四大传统节日。2006年列入第一批国家级非物质文化遗产名录。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('重阳节', '全国', '重阳节', '农历九月初九，习俗包括登高赏秋、喝菊花酒、吃重阳糕。当今重阳节日活动的两大主题是登高赏秋与感恩敬老。2006年列入第一批国家级非物质文化遗产名录。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('腊八节', '全国', '腊八节', '农历十二月初八，家家户户吃腊八粥，用五谷杂粮加各种干果、糖煮成的粥。是佛教节日，也是中国传统民俗节日。', '存续', '中国非物质文化遗产网/民俗资料', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('除夕', '全国', '春节', '农历腊月最后一天，是春节的前夜。全家团聚吃年夜饭，守岁迎新，放鞭炮驱邪避灾。与清明节、七月半、重阳节并称中国传统四大祭祖节日。', '存续', '中国非物质文化遗产网/民俗资料', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('冬至', '全国', '冬至', '二十四节气之一，北半球白昼最短的一天。民间有吃饺子、汤圆等习俗，寓意团圆。有冬至大如年的说法。', '存续', '中国非物质文化遗产网/民俗资料', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('立春', '全国', '立春', '二十四节气之首，标志着春季的开始。民间有咬春习俗，吃春饼、春卷等，寓意迎春接福。', '存续', '中国非物质文化遗产网/民俗资料', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('北京地坛庙会', '北京市东城区', '春节', '地坛春节文化庙会是北京历史最悠久的庙会之一，始于1985年。庙会以地道民俗、传统民间特色闻名，有仿清祭地表演、民间花会、舞狮舞龙等传统活动。', '存续', '中国非物质文化遗产网/地方民俗', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('北京龙潭庙会', '北京市东城区', '春节', '龙潭庙会是北京著名春节庙会，以民间体育竞技、非遗展示为特色。有摸石猴、打金钱眼等传统民俗活动，以及抖空竹、踢毽子等北京传统体育项目。', '存续', '中国非物质文化遗产网/地方民俗', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('北京厂甸庙会', '北京市西城区', '春节', '厂甸庙会是北京八大庙会之首，始于清乾隆年间。以文市特色著称，有售卖古玩字画、文房四宝的摊位，以及糖葫芦、豆汁儿等北京传统小吃。', '存续', '中国非物质文化遗产网/地方民俗', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('北京白云观庙会', '北京市西城区', '春节', '白云观庙会始于元代，是北京著名道教庙会。有摸石猴、打金钱眼、顺星祈福等传统活动，以及道教音乐、道教法事等宗教文化展示。', '存续', '中国非物质文化遗产网/地方民俗', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('北京妙峰山庙会', '北京市门头沟区', '农历四月初一', '妙峰山庙会是华北地区规模最大的庙会，始于明代。以娘娘崇拜为核心，有朝山进香、民间花会表演等活动，被誉为中国民俗学的发源地。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('天津皇会', '天津市', '农历三月二十三', '天津皇会是祭祀妈祖的大型民俗活动，又称娘娘会。有仪仗、法鼓、高跷、秧歌等多种民间花会表演，是天津地区最盛大的传统民俗活动。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('天津杨柳青年画', '天津市西青区', '春节', '杨柳青年画是中国著名民间木版年画，与苏州桃花坞年画并称南桃北柳。以木版套印和手工彩绘相结合，题材多为吉祥喜庆内容，是春节装饰的重要元素。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('河北蔚县打树花', '河北省张家口市蔚县', '元宵节', '蔚县暖泉镇传统社火活动，将熔化的铁水泼洒在城墙上，迸溅出璀璨火花。源于明代铁匠作坊，有500余年历史，被誉为火树金花不夜天。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('河北吴桥杂技', '河北省沧州市吴桥县', '其他民俗', '吴桥是中国杂技之乡，杂技历史悠久，技艺精湛。包括魔术、马戏、杂技等多种表演形式，被誉为世界杂技艺术的摇篮。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('山西寒食节', '山西省介休市', '清明节', '寒食节在清明节前一二日，禁火冷食，纪念介子推。山西介休是寒食节发源地，当地有禁火、扫墓、荡秋千、蹴鞠等传统习俗。', '存续', '中国非物质文化遗产网/地方民俗', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('山西晋祠庙会', '山西省太原市晋源区', '农历七月初二', '晋祠庙会是太原地区历史悠久的传统庙会，以祭祀圣母为中心。有传统戏曲表演、民间花会、物资交流等活动，是山西重要的民俗文化活动。', '存续', '中国非物质文化遗产网/地方民俗', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('山西柳林盘子会', '山西省吕梁市柳林县', '元宵节', '柳林盘子会是元宵节期间的传统民俗活动，以供奉盘子（神龛）为核心。有搭盘子、转盘子、闹社火等活动，是晋西地区独特的民俗景观。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('内蒙古那达慕大会', '内蒙古自治区', '夏季', '蒙古族传统节日，每年七八月间举行，有赛马、摔跤、叼羊等体育活动。那达慕是蒙古语娱乐或游戏的意思，是蒙古族人民展示勇武和技艺的盛会。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('内蒙古祭敖包', '内蒙古自治区', '农历五月十三', '蒙古族传统祭祀活动，有200多年历史。人们通过祭祀敖包神灵，表达人与自然和谐相处的理念，体现蒙古族崇拜苍天万物的游牧文化特色。', '存续', '中国非物质文化遗产网/地方民俗', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('辽宁海城高跷', '辽宁省鞍山市海城市', '元宵节', '海城高跷是东北地区最具代表性的高跷表演之一，表演者脚踩高跷，扮成各种角色进行表演。技艺高超，动作惊险，是元宵节期间的重要民俗活动。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('吉林朝鲜族农乐舞', '吉林省延边朝鲜族自治州', '秋季', '朝鲜族传统舞蹈，源于农耕文化，表现农民劳动和丰收的喜悦。舞蹈节奏明快，动作优美，是朝鲜族最具代表性的民间舞蹈。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('黑龙江赫哲族鱼皮制作技艺', '黑龙江省同江市', '其他民俗', '赫哲族传统手工技艺，用鱼皮制作衣服、鞋子等生活用品。鱼皮衣轻便保暖，防水耐磨，是赫哲族适应寒冷地区渔猎生活的智慧结晶。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('上海城隍庙庙会', '上海市黄浦区', '春节', '上海城隍庙庙会是上海地区著名的传统庙会，以祈福、商贸、娱乐为主要内容。有传统小吃、手工艺品、民间表演等，是老上海民俗文化的集中展示。', '存续', '中国非物质文化遗产网/地方民俗', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('江苏苏州评弹', '江苏省苏州市', '其他民俗', '苏州地区传统曲艺形式，包括评话和弹词两种。评弹用苏州方言表演，说噱弹唱，是江南水乡文化的重要代表。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('江苏苏州端午习俗', '江苏省苏州市', '端午节', '苏州地区独特的端午习俗，除了吃粽子、赛龙舟外，还有挂钟馗像、贴五毒符、饮雄黄酒、佩香囊等习俗。苏州是端午节纪念伍子胥的发源地。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('江苏南京秦淮灯会', '江苏省南京市秦淮区', '元宵节', '秦淮灯会是南京地区著名的传统民俗活动，始于南朝。以夫子庙、秦淮河为核心，有各式彩灯、民间表演、传统小吃等，被誉为天下第一灯会。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('浙江绍兴黄酒酿制习俗', '浙江省绍兴市', '立冬', '绍兴黄酒是中国最古老的酒类之一，酿制工艺复杂。立冬是绍兴黄酒开酿的日子，有祭酒神、开酿仪式等传统习俗。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('浙江龙泉青瓷烧制技艺', '浙江省丽水市龙泉市', '其他民俗', '龙泉青瓷是中国陶瓷史上烧制时间最长、影响最大的窑系之一。青瓷以釉色青翠、造型典雅著称，有雨过天青云破处的美誉。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('浙江宁波象山渔民开洋节', '浙江省宁波市象山县', '农历三月', '象山渔民开洋节是渔民出海捕鱼前的祭祀活动，有祭海、祭船、祭网仪式，祈求风调雨顺、鱼虾满舱，是东海渔区重要的海洋民俗文化。', '存续', '中国非物质文化遗产网/地方民俗', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('安徽黄山庙会', '安徽省黄山市', '农历三月十五', '黄山地区传统庙会活动，有祭祀山神、祈福许愿、民间文艺表演等。黄山是道教和佛教圣地，庙会融合了多种宗教和民俗元素。', '存续', '中国非物质文化遗产网/地方民俗', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('安徽黄梅戏', '安徽省安庆市', '其他民俗', '安徽地方戏曲剧种，起源于湖北黄梅，发展于安徽安庆。唱腔淳朴流畅，表演质朴细腻，以《天仙配》《女驸马》等剧目闻名全国。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('安徽凤阳花鼓', '安徽省滁州市凤阳县', '其他民俗', '凤阳花鼓是流传于凤阳地区的民间歌舞，有凤阳花鼓、花鼓灯、花鼓戏三种形式。表演欢快热烈，是淮河流域重要的民间艺术。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('福建妈祖祭典', '福建省莆田市湄洲岛', '农历三月二十三', '福建沿海地区祭祀妈祖的传统典礼，妈祖被视为海上保护神。每年妈祖诞辰日举行盛大祭典，包括迎神、上香、献供、诵经等仪式，是闽南地区重要的民俗活动。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('福建客家土楼营造技艺', '福建省龙岩市永定区', '其他民俗', '福建客家人独特的建筑技艺，土楼以生土为主要建筑材料，建筑形式有圆楼、方楼、五凤楼等。土楼营造技艺体现了客家人聚族而居、防御外敌的智慧。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('福建泉州南音', '福建省泉州市', '其他民俗', '泉州南音是中国现存最古老的乐种之一，有音乐活化石之称。演奏形式有指、谱、曲三类，保留了唐宋时期的音乐特色。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('江西景德镇瓷业习俗', '江西省景德镇市', '其他民俗', '景德镇千年瓷都的传统行业习俗，包括瓷业祭祀、行规行约、技艺传承等。瓷工们在特定节日祭拜窑神，祈求烧制顺利，是独特的工业民俗文化遗产。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('江西赣南采茶戏', '江西省赣州市', '其他民俗', '赣南地区传统戏曲剧种，源于茶农劳动生活。表演轻松活泼，唱腔优美动听，具有浓郁的乡土气息，是赣南文化的重要代表。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('山东潍坊风筝', '山东省潍坊市', '清明节', '潍坊是中国风筝之都，清明时节放风筝是当地传统习俗。潍坊风筝以竹为骨、绢为面，造型多样，每年举办国际风筝节。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('山东胶东花饽饽', '山东省烟台市', '春节', '胶东地区传统面食艺术，用面粉捏制各种造型的花饽饽，有龙凤、花卉、动物等造型。春节期间制作花饽饽寓意吉祥如意，是胶东地区重要的年俗。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('山东曲阜孔庙祭孔大典', '山东省济宁市曲阜市', '农历八月二十七', '曲阜孔庙祭孔大典是祭祀孔子的传统典礼，始于汉代。有乐舞、献供、读祝等环节，是儒家文化的重要体现，也是世界祭孔活动的范本。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('河南豫剧', '河南省', '其他民俗', '河南地方戏曲剧种，是中国五大戏曲剧种之一。豫剧唱腔高亢激昂，表演大气磅礴，有东方咏叹调之称，流行于河南及周边省份。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('河南登封中岳庙会', '河南省郑州市登封市', '农历三月和十月', '中岳庙是道教圣地，每年农历三月和十月举行庙会。有祭祀中岳大帝的仪式，还有物资交流、民间艺术表演等活动，是中原地区重要的传统庙会。', '存续', '中国非物质文化遗产网/地方民俗', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('河南浚县正月古庙会', '河南省鹤壁市浚县', '春节', '浚县正月古庙会是华北地区规模最大的传统庙会，有华北第一古庙会之称。有社火表演、民间艺术、物资交流等活动，会期长达一个月。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('河南淮阳太昊陵庙会', '河南省周口市淮阳区', '农历二月二', '淮阳太昊陵庙会是祭祀人祖伏羲的传统庙会，有天下第一庙会之称。有祭祖、担经挑、泥泥狗等独特的民俗活动，会期长达一个月。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('湖北武当山庙会', '湖北省十堰市丹江口市', '春节和三月三', '武当山是道教圣地，每年春节和三月三举行盛大庙会。有朝山进香、道教法会、民间杂技、物资交流等活动，是鄂西北地区重要的传统民俗活动。', '存续', '中国非物质文化遗产网/地方民俗', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('湖北恩施摆手舞', '湖北省恩施土家族苗族自治州', '其他民俗', '土家族传统舞蹈，摆手是土家语跳舞的意思。摆手舞动作古朴粗犷，多在祭祀祖先、庆祝丰收时跳，是土家族文化的重要组成部分。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('湖南汨罗江龙舟习俗', '湖南省岳阳市汨罗市', '端午节', '汨罗江是屈原投江的地方，当地端午节龙舟竞渡习俗历史悠久。龙舟赛前要举行祭龙仪式，船员们喝雄黄酒、系五彩丝，表达对屈原的纪念。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('湖南花鼓戏', '湖南省', '其他民俗', '湖南地方戏曲剧种，形成于清代，以长沙花鼓戏最为著名。表演生动活泼，唱腔优美动听，是湖湘文化的重要载体。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('湖南土家年', '湖南省湘西土家族苗族自治州', '农历腊月二十九', '土家族传统节日，比汉族春节提前一天。有杀年猪、打糍粑、贴春联、跳摆手舞等习俗，是土家族最重要的传统节日。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('湖南苗族赶秋节', '湖南省湘西土家族苗族自治州', '农历立秋', '苗族传统节日，又称秋社。有拦门酒、跳芦笙、唱苗歌、斗牛等活动，是苗族人民庆祝丰收、祈求来年风调雨顺的重要节日。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('广东舞狮', '广东省', '春节', '广东地区春节期间的传统表演艺术，舞狮者装扮成狮子，随着锣鼓声起舞，寓意驱邪避灾、招财进宝。有南狮、北狮之分，广东以醒狮最为著名。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('广东粤剧', '广东省', '其他民俗', '广东地方戏曲剧种，是中国五大戏曲剧种之一。粤剧唱腔优美，表演细腻，融合了唱、做、念、打等多种艺术形式，流行于广东及东南亚地区。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('广东潮汕英歌舞', '广东省汕头市潮阳区', '春节', '潮汕地区传统民间舞蹈，表演者手持英歌槌，按照锣鼓节奏敲打，边舞边行。舞蹈融合了武术、戏剧元素，气势豪迈，是潮汕文化的重要代表。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('广东佛山祖庙庙会', '广东省佛山市', '农历三月三', '佛山祖庙庙会是祭祀北帝的传统庙会，有万福台戏、醒狮表演、武术表演等活动，是岭南地区重要的民俗文化活动。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('广西壮族三月三', '广西壮族自治区', '农历三月初三', '农历三月初三是壮族传统节日，又称歌圩节。青年男女对唱山歌、抛绣球、碰彩蛋，是壮族青年社交和择偶的重要场合，也是壮族文化的集中展示。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('广西瑶族盘王节', '广西壮族自治区', '农历十月十六', '瑶族祭祀祖先盘瓠的传统节日，有祭盘王、唱盘王歌、跳长鼓舞等活动。是瑶族人民纪念祖先、传承文化的重要节日。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('广西侗族大歌', '广西壮族自治区三江侗族自治县', '其他民俗', '侗族传统多声部民歌，有天籁之音的美誉。演唱时无伴奏、无指挥，多声部和谐统一，是侗族文化的重要组成部分。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('广西宾阳炮龙节', '广西壮族自治区南宁市宾阳县', '农历正月十一', '宾阳炮龙节是当地独特的传统民俗活动，舞龙者赤膊舞龙，观众用鞭炮炸龙，寓意炸醒龙王、祈求风调雨顺。场面惊险刺激，被称为东方狂欢节。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('海南黎族三月三', '海南省', '农历三月初三', '黎族传统节日，黎语称孚念孚。男女青年会聚在山坡上对唱民歌、跳竹竿舞、寻找意中人。是黎族人民悼念祖先、喜庆新生、赞美生活的传统节日。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('重庆铜梁龙舞', '重庆市铜梁区', '元宵节', '铜梁龙舞是重庆地区著名的传统舞蹈，以大龙、火龙最为著名。龙身长达数十米，需要数十人共同舞动，气势磅礴，被誉为中华第一龙。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('四川变脸', '四川省', '其他民俗', '川剧表演的特技之一，演员在瞬间变换脸谱，展现人物内心情绪变化。是四川地区独特的传统表演艺术，也是中国传统戏曲文化的瑰宝。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('四川自贡灯会', '四川省自贡市', '元宵节', '自贡地区传统民俗活动，始于唐宋，盛于明清。自贡灯会规模宏大，灯组造型精美，集灯彩、灯雕、灯塑于一体，被誉为天下第一灯。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('四川彝族火把节', '四川省凉山彝族自治州', '农历六月二十四', '彝族最盛大的传统节日，人们点燃火把在田间游走，祈求丰收、驱邪避灾。夜晚举行篝火晚会，青年男女载歌载舞。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('贵州苗族姊妹节', '贵州省黔东南苗族侗族自治州台江县', '农历三月十五', '台江县苗族传统节日，被称为最古老的东方情人节。姑娘们会穿上盛装、戴上银饰，与小伙子们对歌、游方、吃姊妹饭，是苗族青年恋爱社交的节日。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('贵州侗族萨玛节', '贵州省黔东南苗族侗族自治州', '农历正月或二月', '侗族祭祀女性祖先萨玛的传统节日，有祭萨、唱萨玛歌、跳萨玛舞等活动。是侗族母系氏族社会文化的重要遗存。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('贵州水族端节', '贵州省黔南布依族苗族自治州', '农历九月', '水族传统节日，又称瓜节，是水族最盛大的节日。有祭祖、赛马、斗牛、对歌等活动，庆祝丰收、祈求来年风调雨顺。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('云南傣族泼水节', '云南省西双版纳傣族自治州', '公历4月中旬', '傣族传统节日，也是傣族新年。人们用清水相互泼洒，祈求洗去过去一年的不顺，迎接新的一年。是傣族最盛大的节日。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('云南白族三月街', '云南省大理白族自治州', '农历三月十五至二十', '大理白族传统节日，又称观音市。是物资交流和民族文艺活动的盛会，有赛马、对歌、贸易等活动，已有千年历史。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('云南纳西古乐', '云南省丽江市', '其他民俗', '纳西族传统音乐，由白沙细乐和丽江古乐两部分组成。保留了大量唐宋元时期的音乐元素，被誉为音乐活化石。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('云南彝族火把节', '云南省楚雄彝族自治州', '农历六月二十四', '云南彝族最盛大的传统节日，人们点燃火把巡游村寨，祈求丰收、驱邪避灾。有斗牛、赛马、选美、篝火晚会等活动。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('西藏藏戏', '西藏自治区', '其他民俗', '藏族传统戏曲，藏语称阿吉拉姆。藏戏历史悠久，表演形式独特，演员戴着面具表演，讲述佛经故事和历史传说，是藏族文化的瑰宝。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('西藏雪顿节', '西藏自治区拉萨市', '藏历六月三十', '藏族传统节日，又称酸奶节。有展佛、藏戏表演、过林卡等活动。最初是僧人结束夏安居后吃酸奶的节日，后来发展成为综合性民俗节日。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('陕西秦腔', '陕西省', '其他民俗', '中国古老的戏剧之一，起源于陕西、甘肃一带，唱腔高亢激越，表演粗犷豪放。是西北地区重要的传统艺术形式，被誉为黄土高原的摇滚。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('陕西黄陵祭祖', '陕西省延安市黄陵县', '清明节', '黄陵祭祖是祭祀中华民族始祖轩辕黄帝的传统典礼，始于汉代。有公祭、民祭两种形式，是海内外华人共同参与的盛大祭祀活动。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('陕西安塞腰鼓', '陕西省延安市安塞区', '春节', '安塞腰鼓是陕北地区传统民俗舞蹈，气势磅礴，豪迈奔放。有天下第一鼓之称，是黄土高原人民精神风貌的集中体现。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('甘肃兰州太平鼓', '甘肃省兰州市', '春节', '兰州地区春节传统表演艺术，是一种带有浓郁西北风情的汉族民俗舞蹈。表演者手持太平鼓，边击边舞，寓意天下太平、五谷丰登。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('青海塔尔寺酥油花', '青海省西宁市湟中区', '元宵节', '塔尔寺传统宗教艺术，用酥油捏制各种佛像、花卉、建筑等造型。酥油花色彩艳丽，造型精美，每年正月十五在塔尔寺展出，吸引众多信众和游客。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('青海土族纳顿节', '青海省海东市', '农历七月', '土族传统节日，意为娱乐玩耍。有傩戏表演、面具舞等活动，庆祝丰收、感谢神灵。是土族最盛大的传统节日。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('宁夏回族花儿', '宁夏回族自治区', '其他民俗', '回族传统民歌形式，花儿又称少年。曲调高亢悠扬，歌词多表达爱情和生活中的情感，在西北地区广泛流传，被誉为西北之魂。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('新疆古尔邦节', '新疆维吾尔自治区', '伊斯兰教历十二月十日', '回族、维吾尔族等信仰伊斯兰教民族的传统节日，又称宰牲节。节前打扫房屋、制作糕点，节日当天穆斯林沐浴后参加会礼，还有宰羊、赛马、摔跤等活动。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');
INSERT INTO FolkloreEntries (Title, Region, Festival, Description, Status, Source, CreatedAt) VALUES ('新疆维吾尔族麦西热甫', '新疆维吾尔自治区', '其他民俗', '维吾尔族传统歌舞聚会形式，有歌舞、游戏、诗词朗诵等活动。是维吾尔族人民社交娱乐、传承文化的重要方式。', '存续', '中国非物质文化遗产网/国家级非遗名录', '2025-04-04T12:00:00Z');